(function () {
  'use strict';
  const nav = document.querySelector('.nav');
  if (nav) {
    let lastY = window.scrollY;
    let ticking = false;
    let direction = 'down';
    const SHRINK = 24;
    const FLOAT = 100;
    const DELTA = 6;
    const getHideAfter = () => window.innerHeight || document.documentElement.clientHeight || 800;
    const update = () => {
      const y = window.scrollY;
      const dy = y - lastY;
      const hideAfter = getHideAfter();
      nav.classList.toggle('scrolled', y > SHRINK);
      nav.classList.toggle('floating', y > FLOAT);
      if (Math.abs(dy) > DELTA) {
        if (dy > 0) direction = 'down';
        else if (dy < 0) direction = 'up';
      }
      let opacity = 1;
      if (direction === 'down' && y > FLOAT && !nav.classList.contains('open')) {
        const prog = Math.min(1, Math.max(0, (y - FLOAT) / (hideAfter - FLOAT)));
        opacity = 1 - prog;
      }
      nav.style.setProperty('--nav-opacity', opacity.toFixed(3));
      lastY = y;
      ticking = false;
    };
    window.addEventListener('scroll', () => {
      if (!ticking) {
        requestAnimationFrame(update);
        ticking = true;
      }
    }, { passive: true });
    update();
  }
  const burger = document.querySelector('.nav__burger');
  if (burger && nav) {
    burger.addEventListener('click', () => {
      const isOpen = nav.classList.toggle('open');
      burger.setAttribute('aria-expanded', String(isOpen));
      burger.setAttribute('aria-label', isOpen ? 'Chiudi menu di navigazione' : 'Apri menu di navigazione');
    });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && nav.classList.contains('open')) {
        nav.classList.remove('open');
        burger.setAttribute('aria-expanded', 'false');
        burger.focus();
      }
    });
  }
  document.querySelectorAll('.nav__dropdown-trigger').forEach((trigger) => {
    trigger.addEventListener('click', (e) => {
      if (!nav || !nav.classList.contains('open')) return;
      const dd = trigger.closest('.nav__dropdown');
      if (!dd) return;
      const isChevron = e.target.classList && e.target.classList.contains('nav__dropdown-chevron');
      const isAccordionOpen = dd.classList.contains('open');
      if (isChevron) {
        e.preventDefault();
        dd.classList.toggle('open');
        trigger.setAttribute('aria-expanded', String(!isAccordionOpen));
      } else if (!isAccordionOpen) {
        e.preventDefault();
        dd.classList.add('open');
        trigger.setAttribute('aria-expanded', 'true');
      }
    });
  });
  document.querySelectorAll('.hero__title.reveal, .page-hero__title.reveal, .section-header h2:not(.visually-hidden), .cta-block__title').forEach((el) => {
    if (el.dataset.splitDone) return;
    const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT);
    const textNodes = [];
    let tn;
    while ((tn = walker.nextNode())) textNodes.push(tn);
    let wordIndex = 0;
    textNodes.forEach((node) => {
      if (!node.nodeValue.trim()) return;
      const frag = document.createDocumentFragment();
      node.nodeValue.split(/(\s+)/).forEach((part) => {
        if (part === '') return;
        if (/^\s+$/.test(part)) {
          frag.appendChild(document.createTextNode(part));
        } else {
          const outer = document.createElement('span');
          outer.className = 'word';
          const inner = document.createElement('span');
          inner.className = 'word__inner';
          inner.textContent = part;
          inner.style.transitionDelay = (wordIndex * 70) + 'ms';
          wordIndex += 1;
          outer.appendChild(inner);
          frag.appendChild(outer);
        }
      });
      node.parentNode.replaceChild(frag, node);
    });
    el.dataset.splitDone = '1';
    el.classList.add('split-reveal');
  });
  const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  const revealEls = document.querySelectorAll('.reveal');
  if (prefersReducedMotion) {
    revealEls.forEach((el) => el.classList.add('is-in'));
  } else if ('IntersectionObserver' in window && revealEls.length) {
    const obs = new IntersectionObserver((entries) => {
      entries.forEach((e) => {
        if (e.isIntersecting) {
          e.target.classList.add('is-in');
          obs.unobserve(e.target);
        }
      });
    }, { threshold: 0.14, rootMargin: '0px 0px -8% 0px' });
    revealEls.forEach((el) => obs.observe(el));
  } else {
    revealEls.forEach((el) => el.classList.add('is-in'));
  }
  const statNums = document.querySelectorAll('.stat__num');
  if (statNums.length) {
    statNums.forEach((el) => {
      if (el.dataset.countPrepared) return;
      const raw = el.textContent.trim();
      const m = raw.match(/^(\d+)(.*)$/);
      if (!m) return;
      el.dataset.target = m[1];
      el.dataset.suffix = m[2] || '';
      el.dataset.countPrepared = '1';
      if (!prefersReducedMotion) {
        el.textContent = '0' + (m[2] || '');
      }
    });
    if (!prefersReducedMotion && 'IntersectionObserver' in window) {
      const easeOutCubic = (t) => 1 - Math.pow(1 - t, 3);
      const statObs = new IntersectionObserver((entries) => {
        entries.forEach((e) => {
          if (!e.isIntersecting) return;
          const el = e.target;
          if (el.dataset.counted) return;
          el.dataset.counted = '1';
          const target = parseInt(el.dataset.target, 10);
          const suffix = el.dataset.suffix || '';
          const duration = 1800;
          const startTs = performance.now();
          const tick = (now) => {
            const t = Math.min(1, (now - startTs) / duration);
            const val = Math.round(target * easeOutCubic(t));
            el.textContent = val + suffix;
            if (t < 1) requestAnimationFrame(tick);
          };
          requestAnimationFrame(tick);
          statObs.unobserve(el);
        });
      }, { threshold: 0.4 });
      statNums.forEach((el) => statObs.observe(el));
    }
  }
  const fp = document.querySelector('.footer-particles');
  if (fp && !prefersReducedMotion && window.matchMedia('(hover: hover) and (pointer: fine)').matches) {
    const canvas = fp.querySelector('.footer-particles__canvas');
    const inner = fp.querySelector('.footer-particles__inner');
    if (canvas && canvas.getContext && inner) {
      const ctx = canvas.getContext('2d');
      let particles = [];
      let mouseX = -10000, mouseY = -10000;
      let dpr = Math.min(window.devicePixelRatio || 1, 2);
      let raf = 0;
      let started = false;
      let cssW = 0, cssH = 0;
      const setup = () => {
        const rect = inner.getBoundingClientRect();
        cssW = rect.width;
        cssH = rect.height;
        canvas.width = Math.round(cssW * dpr);
        canvas.height = Math.round(cssH * dpr);
        canvas.style.width = cssW + 'px';
        canvas.style.height = cssH + 'px';
        ctx.setTransform(1, 0, 0, 1, 0, 0);
        ctx.scale(dpr, dpr);
        const off = document.createElement('canvas');
        off.width = Math.max(2, Math.round(cssW));
        off.height = Math.max(2, Math.round(cssH));
        const octx = off.getContext('2d');
        const fontSize = Math.min(cssW / 5.2, cssH * 0.92);
        octx.font = '700 ' + fontSize.toFixed(0) + "px 'Switzer', system-ui, -apple-system, sans-serif";
        octx.textAlign = 'left';
        octx.textBaseline = 'middle';
        octx.fillStyle = '#fff';
        octx.fillText('EURISKO', 0, off.height / 2);
        const data = octx.getImageData(0, 0, off.width, off.height).data;
        particles = [];
        const step = cssW > 900 ? 3 : (cssW > 600 ? 4 : 6);
        for (let y = 0; y < off.height; y += step) {
          for (let x = 0; x < off.width; x += step) {
            const idx = (y * off.width + x) * 4 + 3;
            if (data[idx] > 128) {
              particles.push({
                bx: x,
                by: y,
                x: x + (Math.random() - 0.5) * 200,
                y: y + (Math.random() - 0.5) * 200,
                vx: 0,
                vy: 0,
                size: 0.9 + Math.random() * 0.6
              });
            }
          }
        }
      };
      const REPULSE_RADIUS = 90;
      const R2 = REPULSE_RADIUS * REPULSE_RADIUS;
      const draw = () => {
        ctx.clearRect(0, 0, cssW, cssH);
        ctx.fillStyle = 'rgba(245, 241, 232, 0.95)';
        for (let i = 0; i < particles.length; i++) {
          const p = particles[i];
          const dx = p.x - mouseX;
          const dy = p.y - mouseY;
          const d2 = dx * dx + dy * dy;
          if (d2 < R2) {
            const dist = Math.sqrt(d2) || 1;
            const force = (REPULSE_RADIUS - dist) / dist;
            p.vx += dx * force * 0.04;
            p.vy += dy * force * 0.04;
          }
          p.vx += (p.bx - p.x) * 0.04;
          p.vy += (p.by - p.y) * 0.04;
          p.vx *= 0.82;
          p.vy *= 0.82;
          p.x += p.vx * 0.75;
          p.y += p.vy * 0.75;
          ctx.beginPath();
          ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
          ctx.fill();
        }
        raf = requestAnimationFrame(draw);
      };
      const start = () => {
        if (started) return;
        started = true;
        fp.classList.add('is-active');
        setup();
        draw();
      };
      const initWhenReady = () => {
        if ('IntersectionObserver' in window) {
          const obs = new IntersectionObserver((entries) => {
            if (entries.some((e) => e.isIntersecting)) {
              start();
              obs.disconnect();
            }
          }, { threshold: 0.05 });
          obs.observe(fp);
        } else {
          start();
        }
      };
      if (document.fonts && document.fonts.ready) {
        document.fonts.ready.then(initWhenReady, initWhenReady);
      } else {
        initWhenReady();
      }
      fp.addEventListener('mousemove', (e) => {
        const rect = canvas.getBoundingClientRect();
        mouseX = e.clientX - rect.left;
        mouseY = e.clientY - rect.top;
      });
      fp.addEventListener('mouseleave', () => {
        mouseX = -10000;
        mouseY = -10000;
      });
      let resizeT = 0;
      window.addEventListener('resize', () => {
        clearTimeout(resizeT);
        resizeT = setTimeout(() => { if (started) setup(); }, 200);
      });
    }
  }
  if (!prefersReducedMotion && window.matchMedia('(hover: hover) and (pointer: fine)').matches) {
    const strength = 0.28;
    document.querySelectorAll('.btn').forEach((btn) => {
      btn.addEventListener('mousemove', (e) => {
        const rect = btn.getBoundingClientRect();
        const dx = (e.clientX - (rect.left + rect.width / 2)) * strength;
        const dy = (e.clientY - (rect.top + rect.height / 2)) * strength;
        btn.style.setProperty('--mx', dx.toFixed(2) + 'px');
        btn.style.setProperty('--my', dy.toFixed(2) + 'px');
      });
      btn.addEventListener('mouseleave', () => {
        btn.style.setProperty('--mx', '0px');
        btn.style.setProperty('--my', '0px');
      });
    });
  }
  const searchTrigger = document.querySelector('.nav__search');
  if (searchTrigger) {
    const isEN = (document.documentElement.lang || 'it').toLowerCase().startsWith('en');
    const t = isEN
      ? { placeholder: 'Search the Eurisko site…', hint: 'Press', empty: 'No results for' }
      : { placeholder: 'Cerca nel sito Eurisko…', hint: 'Premi', empty: 'Nessun risultato per' };
    let searchIndex = null;
    let renderTimer = null;
    const overlay = document.createElement('div');
    overlay.className = 'site-search';
    overlay.setAttribute('aria-hidden', 'true');
    overlay.innerHTML = ''
      + '<div class="site-search__backdrop" aria-hidden="true"></div>'
      + '<div class="site-search__panel" role="dialog" aria-modal="true" aria-label="Search">'
      +   '<button class="site-search__close" aria-label="' + (isEN ? 'Close search' : 'Chiudi ricerca') + '">&times;</button>'
      +   '<div class="site-search__input-wrap">'
      +     '<svg class="site-search__icon" viewBox="0 0 24 24" aria-hidden="true"><circle cx="11" cy="11" r="7"/><path d="m20 20-4-4"/></svg>'
      +     '<input type="search" class="site-search__input" placeholder="' + t.placeholder + '" autocomplete="off" spellcheck="false" />'
      +   '</div>'
      +   '<div class="site-search__hint">' + t.hint + ' <kbd>ESC</kbd> ' + (isEN ? 'to close' : 'per chiudere') + ' · <kbd>Ctrl</kbd>+<kbd>' + (isEN ? 'Click' : 'Clic') + '</kbd> ' + (isEN ? 'to open in new tab' : 'per aprire in nuova scheda') + '</div>'
      +   '<div class="site-search__results" role="list" aria-live="polite"></div>'
      + '</div>';
    document.body.appendChild(overlay);
    const inputEl = overlay.querySelector('.site-search__input');
    const resultsEl = overlay.querySelector('.site-search__results');
    const closeBtn = overlay.querySelector('.site-search__close');
    const backdrop = overlay.querySelector('.site-search__backdrop');
    const escapeHtml = (s) => String(s).replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
    const escapeRegex = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const highlight = (text, tokens) => {
      let out = escapeHtml(text);
      tokens.forEach((tok) => {
        const re = new RegExp('(' + escapeRegex(tok) + ')', 'gi');
        out = out.replace(re, '<mark>$1</mark>');
      });
      return out;
    };
    const snippet = (text, tokens, max) => {
      if (!text) return '';
      if (text.length <= max) return highlight(text, tokens);
      const lower = text.toLowerCase();
      let pos = -1;
      tokens.forEach((tok) => {
        const i = lower.indexOf(tok);
        if (i >= 0 && (pos === -1 || i < pos)) pos = i;
      });
      if (pos === -1) return highlight(text.slice(0, max) + '…', tokens);
      const start = Math.max(0, pos - 40);
      const end = Math.min(text.length, start + max);
      return (start > 0 ? '…' : '') + highlight(text.slice(start, end), tokens) + (end < text.length ? '…' : '');
    };
    const ensureIndex = async () => {
      if (searchIndex) return searchIndex;
      try {
        const res = await fetch('/search-index.json', { cache: 'force-cache' });
        if (!res.ok) throw new Error('HTTP ' + res.status);
        searchIndex = await res.json();
      } catch (err) {
        console.error('search index fetch failed', err);
        searchIndex = [];
      }
      return searchIndex;
    };
    const render = (query) => {
      const q = (query || '').toLowerCase().trim();
      if (!q) { resultsEl.innerHTML = ''; return; }
      const tokens = q.split(/\s+/).filter((tok) => tok.length > 1);
      if (!tokens.length || !searchIndex) { resultsEl.innerHTML = ''; return; }
      const langPref = isEN ? 'en' : 'it';
      const scored = [];
      searchIndex.forEach((entry) => {
        const titleLow = (entry.title || '').toLowerCase();
        const descLow = (entry.description || '').toLowerCase();
        const contentLow = (entry.content || '').toLowerCase();
        let score = 0;
        let allMatch = true;
        for (let i = 0; i < tokens.length; i += 1) {
          const tok = tokens[i];
          let hits = 0;
          if (titleLow.includes(tok)) { score += 10; hits += 10; }
          if (descLow.includes(tok)) { score += 4; hits += 4; }
          if (contentLow.includes(tok)) { score += 1; hits += 1; }
          if (!hits) { allMatch = false; break; }
        }
        if (allMatch && score > 0) {
          if ((entry.lang || 'it').toLowerCase().startsWith(langPref)) score *= 2;
          scored.push({ entry: entry, score: score });
        }
      });
      scored.sort((a, b) => b.score - a.score);
      const top = scored.slice(0, 12);
      if (!top.length) {
        resultsEl.innerHTML = '<div class="site-search__empty">' + t.empty + ' "' + escapeHtml(query) + '"</div>';
        return;
      }
      resultsEl.innerHTML = top.map(function (item, i) {
        const e = item.entry;
        const desc = snippet(e.description, tokens, 160);
        return ''
          + '<a class="site-search__result" href="' + e.url + '" style="animation-delay:' + (i * 30) + 'ms">'
          +   '<span class="site-search__result-title">' + highlight(e.title, tokens) + '</span>'
          +   (desc ? '<span class="site-search__result-desc">' + desc + '</span>' : '')
          +   '<span class="site-search__result-arrow" aria-hidden="true">&rarr;</span>'
          + '</a>';
      }).join('');
    };
    const open = () => {
      overlay.classList.add('open');
      overlay.setAttribute('aria-hidden', 'false');
      document.body.style.overflow = 'hidden';
      ensureIndex().then(() => {  });
      setTimeout(() => inputEl.focus(), 80);
    };
    const close = () => {
      overlay.classList.remove('open');
      overlay.setAttribute('aria-hidden', 'true');
      document.body.style.overflow = '';
      inputEl.value = '';
      resultsEl.innerHTML = '';
    };
    searchTrigger.addEventListener('click', open);
    closeBtn.addEventListener('click', close);
    backdrop.addEventListener('click', close);
    inputEl.addEventListener('input', () => {
      clearTimeout(renderTimer);
      renderTimer = setTimeout(() => render(inputEl.value), 80);
    });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && overlay.classList.contains('open')) close();
      if ((e.key === 'k' || e.key === 'K') && (e.ctrlKey || e.metaKey)) {
        e.preventDefault();
        if (overlay.classList.contains('open')) close(); else open();
      }
    });
  }
  document.querySelectorAll('.marquee__track').forEach((track) => {
    track.innerHTML += track.innerHTML;
  });
  document.querySelectorAll('[data-year]').forEach((el) => {
    el.textContent = new Date().getFullYear();
  });
  const isEN = (document.documentElement.lang || 'it').toLowerCase().startsWith('en');
  const contactForm = document.querySelector('form.contact');
  if (contactForm) {
    const t = isEN
      ? {
          required: 'This field is required.',
          email: 'Please enter a valid email address.',
          minlength: (n) => `Please enter at least ${n} characters.`,
          privacy: 'You must accept the privacy policy.',
          sending: 'Sending…',
        }
      : {
          required: 'Questo campo è obbligatorio.',
          email: 'Inserisci un indirizzo email valido.',
          minlength: (n) => `Inserisci almeno ${n} caratteri.`,
          privacy: 'Devi accettare la privacy policy.',
          sending: 'Invio in corso…',
        };
    const status = contactForm.querySelector('.form-status');
    const setStatus = (text, state) => {
      if (!status) return;
      status.textContent = text || '';
      if (state) status.dataset.state = state;
      else delete status.dataset.state;
    };
    const showError = (field, message) => {
      field.setAttribute('aria-invalid', 'true');
      const errorEl = document.getElementById(field.id + '-error');
      if (errorEl) {
        errorEl.textContent = message;
        errorEl.hidden = false;
        field.setAttribute('aria-describedby', errorEl.id);
      }
    };
    const clearError = (field) => {
      field.removeAttribute('aria-invalid');
      const errorEl = document.getElementById(field.id + '-error');
      if (errorEl) {
        errorEl.textContent = '';
        errorEl.hidden = true;
      }
    };
    const validateField = (field) => {
      const value = (field.value || '').trim();
      if (field.hasAttribute('required') && field.type !== 'checkbox' && !value) {
        showError(field, t.required);
        return false;
      }
      if (field.type === 'email' && value) {
        const ok = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
        if (!ok) { showError(field, t.email); return false; }
      }
      const min = parseInt(field.getAttribute('minlength') || '0', 10);
      if (min > 0 && value && value.length < min) {
        showError(field, t.minlength(min));
        return false;
      }
      clearError(field);
      return true;
    };
    contactForm.querySelectorAll('input, textarea, select').forEach((field) => {
      if (field.type === 'hidden' || field.name === '_gotcha') return;
      if (field.type !== 'checkbox') {
        field.addEventListener('blur', () => validateField(field));
        field.addEventListener('input', () => {
          if (field.getAttribute('aria-invalid') === 'true') validateField(field);
        });
      }
    });
    contactForm.addEventListener('submit', (e) => {
      let allValid = true;
      let firstInvalid = null;
      contactForm.querySelectorAll('input, textarea, select').forEach((field) => {
        if (field.type === 'hidden' || field.name === '_gotcha') return;
        if (field.type === 'checkbox') {
          if (field.required && !field.checked) {
            allValid = false;
            if (!firstInvalid) firstInvalid = field;
            setStatus(t.privacy, 'error');
          }
          return;
        }
        const ok = validateField(field);
        if (!ok) {
          allValid = false;
          if (!firstInvalid) firstInvalid = field;
        }
      });
      if (!allValid) {
        e.preventDefault();
        if (firstInvalid) firstInvalid.focus();
        return;
      }
      if (typeof grecaptcha !== 'undefined' && contactForm.querySelector('.g-recaptcha')) {
        const token = grecaptcha.getResponse();
        if (!token) {
          e.preventDefault();
          setStatus(isEN ? 'Please confirm you are not a robot.' : 'Conferma di non essere un robot.', 'error');
          return;
        }
      }
      setStatus(t.sending, '');
    });
  }
  const COOKIE_NAME = 'eurisko_consent';
  const COOKIE_DAYS = 365;
  const cookieI18n = isEN
    ? {
        title: 'We value your privacy',
        text: 'We use technical cookies necessary to operate the site. With your consent we may use additional cookies. Read the <a href="cookie-policy.html">Cookie Policy</a> and the <a href="privacy.html">Privacy Policy</a>.',
        accept: 'Accept all',
        reject: 'Reject all',
        custom: 'Customize',
        save: 'Save preferences',
        techName: 'Technical (always active)',
        techDesc: 'Necessary for the proper functioning of the site. Cannot be disabled.',
        analyticsName: 'Analytics',
        analyticsDesc: 'Help us understand how visitors use the site, in aggregate and anonymous form.',
        marketingName: 'Marketing',
        marketingDesc: 'Used to show personalized content. Currently not active.',
        reopen: 'Cookie settings',
        bannerLabel: 'Cookie consent',
      }
    : {
        title: 'Rispettiamo la tua privacy',
        text: 'Utilizziamo cookie tecnici necessari al funzionamento del sito. Con il tuo consenso possiamo utilizzare cookie aggiuntivi. Leggi la <a href="cookie-policy.html">Cookie Policy</a> e la <a href="privacy.html">Privacy Policy</a>.',
        accept: 'Accetta tutti',
        reject: 'Rifiuta tutti',
        custom: 'Personalizza',
        save: 'Salva preferenze',
        techName: 'Tecnici (sempre attivi)',
        techDesc: 'Necessari al corretto funzionamento del sito. Non disattivabili.',
        analyticsName: 'Analitici',
        analyticsDesc: 'Ci aiutano a capire come i visitatori usano il sito, in forma aggregata e anonima.',
        marketingName: 'Marketing',
        marketingDesc: 'Utilizzati per mostrare contenuti personalizzati. Attualmente non attivi.',
        reopen: 'Impostazioni cookie',
        bannerLabel: 'Consenso cookie',
      };
  function getCookie(name) {
    const match = document.cookie.match(new RegExp('(?:^|; )' + name.replace(/([.$?*|{}()\[\]\\\/+^])/g, '\\$1') + '=([^;]*)'));
    return match ? decodeURIComponent(match[1]) : null;
  }
  function setCookie(name, value, days) {
    const d = new Date();
    d.setTime(d.getTime() + days * 86400000);
    const secure = location.protocol === 'https:' ? '; Secure' : '';
    document.cookie = name + '=' + encodeURIComponent(value) + '; expires=' + d.toUTCString() + '; path=/; SameSite=Lax' + secure;
  }
  function readConsent() {
    try {
      const raw = getCookie(COOKIE_NAME);
      if (!raw) return null;
      return JSON.parse(raw);
    } catch (e) { return null; }
  }
  function saveConsent(consent) {
    setCookie(COOKIE_NAME, JSON.stringify(Object.assign({ ts: Date.now(), v: 1 }, consent)), COOKIE_DAYS);
  }
  let bannerEl = null;
  let lastFocusedBeforeBanner = null;
  function buildBanner() {
    const banner = document.createElement('div');
    banner.className = 'cookie-banner';
    banner.id = 'cookie-banner';
    banner.setAttribute('role', 'dialog');
    banner.setAttribute('aria-modal', 'false');
    banner.setAttribute('aria-labelledby', 'cookie-banner-title');
    banner.setAttribute('aria-describedby', 'cookie-banner-text');
    banner.setAttribute('aria-label', cookieI18n.bannerLabel);
    banner.innerHTML = `
      <h2 class="cookie-banner__title" id="cookie-banner-title">${cookieI18n.title}</h2>
      <p class="cookie-banner__text" id="cookie-banner-text">${cookieI18n.text}</p>
      <div class="cookie-banner__actions">
        <button type="button" class="cookie-banner__btn cookie-banner__btn--ghost" data-cookie-action="custom">${cookieI18n.custom}</button>
        <button type="button" class="cookie-banner__btn cookie-banner__btn--secondary" data-cookie-action="reject">${cookieI18n.reject}</button>
        <button type="button" class="cookie-banner__btn cookie-banner__btn--primary" data-cookie-action="accept">${cookieI18n.accept}</button>
      </div>
      <div class="cookie-banner__panel" id="cookie-banner-panel" hidden>
        <div class="cookie-banner__category">
          <div class="cookie-banner__category-info">
            <span class="cookie-banner__category-name">${cookieI18n.techName}</span>
            <p class="cookie-banner__category-desc">${cookieI18n.techDesc}</p>
          </div>
          <label class="cookie-toggle" aria-label="${cookieI18n.techName}">
            <input type="checkbox" checked disabled aria-checked="true" data-category="technical">
            <span class="cookie-toggle__track"></span>
          </label>
        </div>
        <div class="cookie-banner__category">
          <div class="cookie-banner__category-info">
            <span class="cookie-banner__category-name">${cookieI18n.analyticsName}</span>
            <p class="cookie-banner__category-desc">${cookieI18n.analyticsDesc}</p>
          </div>
          <label class="cookie-toggle" aria-label="${cookieI18n.analyticsName}">
            <input type="checkbox" data-category="analytics" aria-checked="false">
            <span class="cookie-toggle__track"></span>
          </label>
        </div>
        <div class="cookie-banner__category">
          <div class="cookie-banner__category-info">
            <span class="cookie-banner__category-name">${cookieI18n.marketingName}</span>
            <p class="cookie-banner__category-desc">${cookieI18n.marketingDesc}</p>
          </div>
          <label class="cookie-toggle" aria-label="${cookieI18n.marketingName}">
            <input type="checkbox" data-category="marketing" aria-checked="false">
            <span class="cookie-toggle__track"></span>
          </label>
        </div>
        <div class="cookie-banner__actions" style="margin-top: 16px;">
          <button type="button" class="cookie-banner__btn cookie-banner__btn--primary" data-cookie-action="save">${cookieI18n.save}</button>
        </div>
      </div>
    `;
    return banner;
  }
  function getFocusable(root) {
    return Array.from(root.querySelectorAll('button:not([disabled]), [href], input:not([disabled]), select, textarea, [tabindex]:not([tabindex="-1"])'));
  }
  function trapFocus(e) {
    if (!bannerEl || e.key !== 'Tab') return;
    const focusables = getFocusable(bannerEl);
    if (!focusables.length) return;
    const first = focusables[0];
    const last = focusables[focusables.length - 1];
    if (e.shiftKey && document.activeElement === first) {
      e.preventDefault();
      last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
      e.preventDefault();
      first.focus();
    }
  }
  function onKeydown(e) {
    if (!bannerEl) return;
    if (e.key === 'Escape') {
      hideBanner();
    } else {
      trapFocus(e);
    }
  }
  function showBanner() {
    if (bannerEl) return;
    lastFocusedBeforeBanner = document.activeElement;
    bannerEl = buildBanner();
    document.body.appendChild(bannerEl);
    bannerEl.addEventListener('click', onBannerClick);
    document.addEventListener('keydown', onKeydown);
    bannerEl.querySelectorAll('.cookie-toggle input').forEach((cb) => {
      cb.addEventListener('change', () => {
        cb.setAttribute('aria-checked', String(cb.checked));
      });
    });
    const firstBtn = bannerEl.querySelector('button[data-cookie-action="accept"]');
    if (firstBtn) firstBtn.focus();
  }
  function hideBanner() {
    if (!bannerEl) return;
    bannerEl.removeEventListener('click', onBannerClick);
    document.removeEventListener('keydown', onKeydown);
    bannerEl.remove();
    bannerEl = null;
    if (lastFocusedBeforeBanner && typeof lastFocusedBeforeBanner.focus === 'function') {
      lastFocusedBeforeBanner.focus();
    }
  }
  function onBannerClick(e) {
    const target = e.target.closest('[data-cookie-action]');
    if (!target) return;
    const action = target.dataset.cookieAction;
    if (action === 'accept') {
      saveConsent({ technical: true, analytics: true, marketing: true });
      hideBanner();
    } else if (action === 'reject') {
      saveConsent({ technical: true, analytics: false, marketing: false });
      hideBanner();
    } else if (action === 'custom') {
      const panel = bannerEl.querySelector('#cookie-banner-panel');
      if (panel) {
        const wasHidden = panel.hasAttribute('hidden');
        if (wasHidden) panel.removeAttribute('hidden');
        else panel.setAttribute('hidden', '');
        target.setAttribute('aria-expanded', String(wasHidden));
      }
    } else if (action === 'save') {
      const consent = { technical: true, analytics: false, marketing: false };
      bannerEl.querySelectorAll('.cookie-toggle input[data-category]').forEach((cb) => {
        consent[cb.dataset.category] = cb.checked;
      });
      saveConsent(consent);
      hideBanner();
    }
  }
  function reopenBanner() {
    if (bannerEl) return;
    showBanner();
    const consent = readConsent();
    if (consent && bannerEl) {
      const panel = bannerEl.querySelector('#cookie-banner-panel');
      if (panel) {
        panel.removeAttribute('hidden');
        const customBtn = bannerEl.querySelector('[data-cookie-action="custom"]');
        if (customBtn) customBtn.setAttribute('aria-expanded', 'true');
      }
      bannerEl.querySelectorAll('.cookie-toggle input[data-category]').forEach((cb) => {
        const category = cb.dataset.category;
        if (category in consent) {
          cb.checked = !!consent[category];
          cb.setAttribute('aria-checked', String(cb.checked));
        }
      });
    }
  }
  function injectCookieReopenLink() {
    const metaContainer = document.querySelector('.footer__meta');
    if (!metaContainer) return;
    const linksContainer = metaContainer.lastElementChild;
    if (!linksContainer || linksContainer.tagName !== 'SPAN') return;
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'cookie-reopen';
    btn.textContent = cookieI18n.reopen;
    btn.addEventListener('click', reopenBanner);
    linksContainer.appendChild(btn);
  }
  if (!readConsent()) {
    setTimeout(showBanner, 400);
  }
  injectCookieReopenLink();
  document.querySelectorAll('.hero__bg-video').forEach((v) => {
    const setRate = () => { v.playbackRate = 0.39; };
    if (v.readyState >= 1) setRate();
    else v.addEventListener('loadedmetadata', setRate);
  });
  const phWraps = document.querySelectorAll('.page-hero__media-wrap--reveal');
  if (phWraps.length) {
    if (prefersReducedMotion) {
      phWraps.forEach((w) => w.classList.add('is-revealed'));
    } else {
      if ('IntersectionObserver' in window) {
        const revealObs = new IntersectionObserver((entries) => {
          entries.forEach((e) => {
            if (e.isIntersecting) {
              e.target.classList.add('is-revealed');
              revealObs.unobserve(e.target);
            }
          });
        }, { threshold: 0.3 });
        phWraps.forEach((w) => revealObs.observe(w));
      } else {
        phWraps.forEach((w) => w.classList.add('is-revealed'));
      }
      phWraps.forEach((w) => {
        const media = w.querySelector('.page-hero__media');
        if (!media) return;
        w.addEventListener('mouseenter', () => w.classList.add('is-hovered'));
        w.addEventListener('mousemove', (e) => {
          const rect = w.getBoundingClientRect();
          const px = (e.clientX - rect.left) / rect.width - 0.5;
          const py = (e.clientY - rect.top) / rect.height - 0.5;
          media.style.setProperty('--tilt-x', (px * 16).toFixed(2) + 'deg');
          media.style.setProperty('--tilt-y', (-py * 16).toFixed(2) + 'deg');
        });
        w.addEventListener('mouseleave', () => {
          w.classList.remove('is-hovered');
          media.style.setProperty('--tilt-x', '0deg');
          media.style.setProperty('--tilt-y', '0deg');
        });
      });
    }
  }
  const phVideos = document.querySelectorAll('.page-hero__video');
  if (phVideos.length) {
    phVideos.forEach((v) => {
      const setRate = () => { v.playbackRate = 0.75; };
      if (v.readyState >= 1) setRate();
      else v.addEventListener('loadedmetadata', setRate);
      v.addEventListener('timeupdate', () => {
        if (v.duration && v.currentTime >= v.duration - 0.1) {
          v.currentTime = 0;
        }
      });
    });
    if (prefersReducedMotion) {
      phVideos.forEach((v) => { v.removeAttribute('autoplay'); v.pause(); });
    } else if ('IntersectionObserver' in window) {
      const phObs = new IntersectionObserver((entries) => {
        entries.forEach((e) => {
          const v = e.target;
          if (e.isIntersecting) v.play().catch(() => {});
          else v.pause();
        });
      }, { threshold: 0.1 });
      phVideos.forEach((v) => phObs.observe(v));
    }
  }
})();
